import { Fragment } from 'react';

const terms = [
  { id: 1, word: 'JSX',   definition: 'JavaScript XML — React\'s template syntax' },
  { id: 2, word: 'Props', definition: 'Read-only inputs passed from parent to child' },
  { id: 3, word: 'State', definition: 'Mutable data owned by a component' },
];

function Glossary({ terms }) {
  return (
    <dl>
      {terms.map(t => (
        <Fragment key={t.id}>
          <dt><strong>{t.word}</strong></dt>
          <dd>{t.definition}</dd>
        </Fragment>
      ))}
    </dl>
  );
}

import { Fragment, useState } from 'react';

function ExpandableTable({ rows }) {
  const [expandedId, setExpanded] = useState(null);

  return (
    <table>
      <tbody>
        {rows.map(row => (
          <Fragment key={row.id}>
            <tr onClick={() => setExpanded(id => id === row.id ? null : row.id)}>
              <td>{row.name}</td>
              <td>{row.summary}</td>
              <td>{expandedId === row.id ? '▲' : '▼'}</td>
            </tr>
            {expandedId === row.id && (
              <tr>
                <td colSpan={3}>{row.detail}</td>
              </tr>
            )}
          </Fragment>
        ))}
      </tbody>
    </table>
  );
}

// Component that renders two siblings
function TermRow({ term }) {
  return (
    <>  {/* <-- shorthand is fine HERE because the parent assigns the key */}
      <dt>{term.word}</dt>
      <dd>{term.definition}</dd>
    </>
  );
}

// Parent assigns the key on the component element
function Glossary({ terms }) {
  return (
    <dl>
      {terms.map(t => (
        <TermRow key={t.id} term={t} />  {/* key goes here, on the component */}
      ))}
    </dl>
  );
}

