import { Fragment } from 'react';

interface Term {
  id: number;
  word: string;
  definition: string;
}

function Glossary({ terms }: { terms: Term[] }) {
  return (
    <dl>
      {terms.map((t) => (
        <Fragment key={t.id}>  {/* key: string | number — both valid */}
          <dt>{t.word}</dt>
          <dd>{t.definition}</dd>
        </Fragment>
      ))}
    </dl>
  );
}

