  <dd key={`${t.id}-dd`}>{t.definition}</dd>,
]);

// Fragment form — one key per group (cleaner)
terms.map(t => (
  <Fragment key={t.id}>
    <dt>{t.word}</dt>
    <dd>{t.definition}</dd>
  </Fragment>
));

import { render, screen } from '@testing-library/react';
import { Glossary } from './Glossary';

const TERMS = [
  { id: 1, word: 'JSX',   definition: 'JavaScript XML' },
  { id: 2, word: 'Props', definition: 'Component inputs' },
];

test('renders dt and dd pairs directly inside dl', () => {
  const { container } = render(<Glossary terms={TERMS} />);
  const dl = container.querySelector('dl');

  // Fragment renders nothing — direct children of <dl> are <dt> and <dd>
  const children = [...dl.children];
  expect(children.map(c => c.tagName)).toEqual(['DT', 'DD', 'DT', 'DD']);
  expect(children[0].textContent).toBe('JSX');
  expect(children[1].textContent).toBe('JavaScript XML');
});

test('rerenders correctly when terms reorder', () => {
  const { rerender } = render(<Glossary terms={TERMS} />);
  rerender(<Glossary terms={[TERMS[1], TERMS[0]]} />);

  const { container } = render(<Glossary terms={[TERMS[1], TERMS[0]]} />);
  const dl = container.querySelector('dl');
  const children = [...dl.children];
  expect(children[0].textContent).toBe('Props'); // now first
  expect(children[2].textContent).toBe('JSX');   // now second
});

import { Fragment } from 'react';

function OrderTable({ items }) {
  return (
    <table>
      <tbody>
        {items.map(item => (
          <Fragment key={item.id}>
            <tr>
              <td>{item.name}</td>
              <td>${item.price}</td>
            </tr>
            {/* Discount row only appears when discount > 0 */}
            {item.discount > 0 && (
              <tr className="discount-row">
                <td colSpan={2}>
                  Discount: -${item.discount}
                </td>
              </tr>
            )}
          </Fragment>
        ))}
      </tbody>
    </table>
  );
}

import { Fragment } from 'react';

function MixedList({ items }) {
  return (
    <dl>
      {items.map(item =>
        item.type === 'section' ? (
          // Section headers: single <dt>, no <dd>
          <dt key={item.id} className="section-header">
            {item.label}
          </dt>
        ) : (
          // Regular items: <dt>/<dd> pair
          <Fragment key={item.id}>
            <dt>{item.term}</dt>
            <dd>{item.definition}</dd>
          </Fragment>
        )
      )}
    </dl>
  );
}

import { Fragment } from 'react';

function CategoryBlock({ category }) {
  return (
    // Outer Fragment: needs key (set by parent .map())
    // This is the component's return value — parent assigns key={category.id}
    <>
      <dt className="category">{category.name}</dt>
      {category.terms.map(term => (
        // Inner keyed Fragment for each term pair
        <Fragment key={term.id}>
          <dt>{term.word}</dt>
          <dd>{term.definition}</dd>
        </Fragment>
      ))}
    </>
  );
}

function NestedGlossary({ categories }) {
  return (
    <dl>
      {categories.map(cat => (
        // key goes on the component element — outer <> inside component is fine
        <CategoryBlock key={cat.id} category={cat} />
      ))}
    </dl>
  );
}

